type ResizeRequest struct {
	FilePath string
	Width    int
	Height   int
}

type ResizeResponse struct {
	FilePath string
	Width    int
	Height   int
}

type ImageServer struct {
	httpServer *http.Server
	images     map[string]*list.Element
	mu         sync.Mutex
	chanRes    chan ResizeRequest
	chanResp   chan ResizeResponse
}

func NewImageServer() *ImageServer {
	server := &ImageServer{
		images:     make(map[string]*list.Element),
		chanRes:    make(chan ResizeRequest, 100),
		chanResp:   make(chan ResizeResponse, 100),
	}
	server.httpServer = &http.Server{
		Addr:              ":8080",
		Handler:           server.handleRequests,
		MaxHeaderBytes:    1 << 20,
		IdleTimeout:       15 * time.Second,
		ReadTimeout:       15 * time.Second,
		WriteTimeout:      15 * time.Second,
	}
	return server
}

func (s *ImageServer) handleRequests(w http.ResponseWriter, r *http.Request) {
	if r.Method != "POST" {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Parse JSON body
	var req ResizeRequest
	err := json.NewDecoder(r.Body).Decode(&req)
	if err != nil {
		http.Error(w, "Invalid JSON", http.StatusBadRequest)
		return
	}

	// Check if file exists
	if !filepath.Exists(req.FilePath) {
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}

	// Add to images map
	s.mu.Lock()
	s.images[req.FilePath] = list.NewElement(s.images, req.FilePath)
	s.mu.Unlock()

	// Send to Goroutine
	go s.processResizeRequest(req)
}

func (s *ImageServer) processResizeRequest(req ResizeRequest) {
	// Simulate image processing
	time.Sleep(1 * time.Second)

	// Create response
	resp := ResizeResponse{
		FilePath: req.FilePath,
		Width:    req.Width,
		Height:   req.Height,
	}

	// Send response back
	s.chanResp <- resp
}

func main() {
	server := NewImageServer()
	fmt.Println("Server started on :8080")
	if err := server.httpServer.ListenAndServe(); err != nil {
		fmt.Println("Server error:", err)
	}
}

