func (s *AuthService) RegisterUser(username, token string) bool {
	s.mu.Lock()
	defer s.mu.Unlock()

	if _, exists := s.users[username]; exists {
		return false
	}

	user := &User{
		ID:   username,
		Name: username,
	}
	s.users[username] = user

	return true
}

func (s *AuthService) Authenticate(username, token string) AuthResponse {
	s.mu.Lock()
	defer s.mu.Unlock()

	user, exists := s.users[username]
	if !exists {
		return AuthResponse{
			Status:  "fail",
			Message: "User not found",
		}
	}

	if user.Token != token {
		return AuthResponse{
			Status:  "fail",
			Message: "Invalid token",
		}
	}

	return AuthResponse{
		Status:  "success",
		Message: "Authentication successful",
	}
