    Penny,
    Nickel,
    Dime,
    Quarter,
}

fn convert_currency(coin: Coin, count: u32, from: &str, to: &str) -> u32 {
    match from {
        "USD" => match to {
            "EUR" => {
                match coin {
                    Coin::Penny => count * 0,
                    Coin::Nickel => count * 5,
                    Coin::Dime => count * 10,
                    Coin::Quarter => count * 25,
                }
            },
            "GBP" => {
                match coin {
                    Coin::Penny => count * 1,
                    Coin::Nickel => count * 5,
                    Coin::Dime => count * 10,
                    Coin::Quarter => count * 25,
                }
            },
            _ => 0,
        },
        _ => 0,
    }
}

fn main() {
    let penny_count = 10;
    let nickel_count = 5;
    let dime_count = 2;
    let quarter_count = 1;

    let usd_to_eur = convert_currency(Coin::Penny, penny_count, "USD", "EUR");
    let usd_to_gbp = convert_currency(Coin::Nickel, nickel_count, "USD", "GBP");
    let usd_to_eur = convert_currency(Coin::Dime, dime_count, "USD", "EUR");
    let usd_to_gbp = convert_currency(Coin::Quarter, quarter_count, "USD", "GBP");

    println!("USD to EUR: {}", usd_to_eur);
    println!("USD to GBP: {}", usd_to_gbp);
}
