// EncryptionResult represents the result of a file encryption
type EncryptionResult struct {
	File       string
	Success    bool
	Message    string
}

// EncryptFile encrypts a single file using AES
func EncryptFile(file string, key []byte, outChan chan EncryptionResult) {
	defer close(outChan)

	// Simulate encryption process
	time.Sleep(time.Millisecond * 100)

	// Simulate success or failure
	success := true
	message := "Encryption successful"

	if !success {
		message = "Encryption failed"
	}

	outChan <- EncryptionResult{
		File:       file,
		Success:    success,
		Message:    message,
	}
}

// EncryptDirectory encrypts all files in a directory using Goroutines
func EncryptDirectory(directory string, key []byte, outChan chan EncryptionResult, wg *sync.WaitGroup) {
	defer wg.Done()

	for _, file := range files(directory) {
		go EncryptFile(file, key, outChan)
	}
}

// files returns all files in a directory
func files(path string) []string {
	var files []string
	err := filepath.Walk(path, func(filename string, _ os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if !filename[0:] == "." {
			files = append(files, filename)
		}
		return nil
	})
	return files
}

// Main function
func main() {
	// Example key for AES encryption
	key := []byte("your-secret-key-123")

	// Directory to encrypt
	directory := "./testdir"

	// Channel to receive results
	outChan := make(chan EncryptionResult, 100)

	// Wait group to wait for all goroutines
	wg := &sync.WaitGroup{}

	// Start encryption process
	go EncryptDirectory(directory, key, outChan, wg)

	// Wait for all files to be encrypted
	wg.Wait()

	// Collect and print results
	var results []EncryptionResult
	for result := range outChan {
		results = append(results, result)
	}

	fmt.Println("Encryption results:")
	for _, result := range results {
		if result.Success {
			fmt.Printf("✅ File: %s - %s\n", result.File, result.Message)
		} else {
			fmt.Printf("❌ File: %s - %s\n", result.File, result.Message)
		}
	}
}

