import java.util.PriorityQueue

class TaskScheduler {
    private val priorityQueue = PriorityQueue<Task>()

    fun addTask(priority: Int, task: () -> Unit) {
        priorityQueue.add(Task(priority, task))
    }

    fun executeTasks() {
        while (!priorityQueue.isEmpty()) {
            val task = priorityQueue.poll()
            task?.let { it() }
        }
    }

    class Task(val priority: Int, val task: () -> Unit) {
        override fun toString() = "Task(priority=$priority)"
    }
}

