type Book struct {
	ID       int     `json:"id"`
	Title    string  `json:"title"`
	Author   string  `json:"author"`
	ISBN     string  `json:"isbn"`
	Quantity int     `json:"quantity"`
	CreatedAt string  `json:"created_at"`
	UpdatedAt string  `json:"updated_at"`
}

var db *sql.DB

func initDB() {
	db, _ = sql.Open("postgres", "postgres://user:password@localhost:5432/bookstore")
	db.SetMaxOpenConns(10)
	db.SetMaxIdleConns(5)
}

func main() {
	initDB()
	r := gin.Default()

	// Define routes
	r.POST("/books", createBook)
	r.GET("/books", getBooks)
	r.GET("/books/:id", getBookById)
	r.PUT("/books/:id", updateBook)
	r.DELETE("/books/:id", deleteBook)

	r.Run(":8080")
}

func createBook(c *gin.Context) {
	var book Book
	c.BindJSON(&book)

	// Open database connection
	db.Exec("INSERT INTO books (title, author, isbn, quantity, created_at) VALUES ($1, $2, $3, $4, $5)", 
		book.Title, book.Author, book.ISBN, book.Quantity, book.CreatedAt)
}

func getBooks(c *gin.Context) {
	rows, _ := db.Query("SELECT * FROM books")
	defer rows.Close()

	var books []Book
	for rows.Next() {
		var book Book
		rows.Scan(&book.ID, &book.Title, &book.Author, &book.ISBN, &book.Quantity, &book.CreatedAt, &book.UpdatedAt)
		books = append(books, book)
	}
	c.JSON(200, books)
}

func getBookById(c *gin.Context) {
	id := c.Param("id")
	var book Book
	rows, _ := db.Query("SELECT * FROM books WHERE id = $1", id)
	defer rows.Close()

	if rows.Next() {
		var book Book
		rows.Scan(&book.ID, &book.Title, &book.Author, &book.ISBN, &book.Quantity, &book.CreatedAt, &book.UpdatedAt)
		c.JSON(200, book)
	} else {
		c.JSON(404, gin.H{"error": "Book not found"})
	}
}

func updateBook(c *gin.Context) {
	id := c.Param("id")
	var book Book
	c.BindJSON(&book)

	// Open database connection
	db.Exec("UPDATE books SET title = $1, author = $2, isbn = $3, quantity = $4, updated_at = $5 WHERE id = $6", 
		book.Title, book.Author, book.ISBN, book.Quantity, book.UpdatedAt, id)
}

func deleteBook(c *gin.Context) {
	id := c.Param("id")
	db.Exec("DELETE FROM books WHERE id = $1", id)
}

