def count_warnings(session_id, log_entries):
    warnings = 0
    for entry in log_entries:
        if entry.startswith("WARNING:"):
            warnings += 1
    return warnings

def generator(session_id, log_entries):
    for entry in log_entries:
        yield session_id, count_warnings(session_id, entry)

def main():
    with open('logs.csv', 'r') as csvfile:
        reader = csv.DictReader(csvfile)
        for row in reader:
            session_id = row['session_id']
            log_entries = []
            for i, entry in enumerate(reader):
                if i == 0:
                    continue
                log_entries.append(entry)
            for session_id, warnings in generator(session_id, log_entries):
                print(f"Session ID: {session_id}, Warnings: {warnings}")

