fn convert_temperatures(temperatures: &[f64]) -> Vec<f64> {
    temperatures
        .iter()
        .map(|&temp| match temp {
            // Freezing: below 0°C
            temp if temp < 0.0 => temp * 9.0 / 5.0 + 32.0,
            // Cold: 0°C to 15°C
            temp if temp >= 0.0 && temp < 15.0 => temp * 9.0 / 5.0 + 32.0,
            // Warm: 16°C to 30°C
            temp if temp >= 16.0 && temp < 30.0 => temp * 9.0 / 5.0 + 32.0,
            // Hot: above 30°C
            temp => temp * 9.0 / 5.0 + 32.0,
        })
        .collect()
}
